SELECT
FROM t_song s LEFT JOIN t_singer sg ON s.singer_id = sg.id AND sg.deleted = 0 LEFT JOIN t_category c ON s.category_id = c.id AND c.deleted = 0 WHERE s.deleted = 0 AND s.id IN
#{id}

SELECT

FROM t_song s
LEFT JOIN t_singer sg ON s.singer_id = sg.id AND sg.deleted = 0
LEFT JOIN t_category c ON s.category_id = c.id AND c.deleted = 0
WHERE s.deleted = 0

    AND s.name LIKE CONCAT('%', #{name}, '%')


    AND s.singer_id = #{singerId}


    AND s.category_id = #{categoryId}


    AND s.language = #{language}


    AND s.status = #{status}

ORDER BY s.id DESC
